#include<bits/stdc++.h>
using namespace std;
map<int,int> odt;
struct node
{
    int l,r;
}a[100010];
int main()
{
    int n,s;
    scanf("%d%d",&n,&s);
    odt[-1e9]=odt[1e9]=-1;
    odt[s]=0;
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&a[i].l,&a[i].r);
    }
    reverse(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        int l=a[i].l,r=a[i].r;
        if(!odt.count(l))
        {
            odt[l]=1e9;
        }
        if(!odt.count(r))
        {
            odt[r]=1e9;
        }
        for(auto it=odt.upper_bound(l);it->first<r;it=odt.erase(it))
        {
            odt[l]=min(odt[l],it->first-l+it->second);
            odt[r]=min(odt[r],r-it->first+it->second);
        }
    }
    int ans=1e9;
    for(auto i:odt)
    {
        ans=min(ans,abs(i.first)+i.second);
    }
    printf("%d",ans);
    return 0;
}
